// Azure-Lily DIMM mac_qk — N=128, d=64
// Generated by gen_dimm_azurelily_full.py

// azurelily_dimm_mac_qk — Q(d=64) × K^T(N=128×d=64) on DSP
// Pipeline: Q SRAM + K SRAM → dsp_mac(K=13) → score SRAM

module azurelily_dimm_mac_qk #(
    parameter N = 128,
    parameter D = 64,
    parameter DATA_WIDTH = 40
)(
    input wire clk, input wire rst,
    input wire valid_q, input wire valid_k,
    input wire ready_n,
    input wire [DATA_WIDTH-1:0] data_in_q,
    input wire [DATA_WIDTH-1:0] data_in_k,
    output wire [DATA_WIDTH-1:0] data_out,
    output wire valid_n
);

    localparam EPW = DATA_WIDTH / 8;
    localparam PACKED_D = 13;

    localparam S_IDLE = 3'd0, S_LOAD_Q = 3'd1, S_LOAD_K = 3'd2,
               S_COMPUTE = 3'd3, S_DRAIN = 3'd4, S_OUTPUT = 3'd5;
    reg [2:0] state;
    reg [4-1:0] q_w_addr, q_r_addr;
    reg [11-1:0] k_w_addr, k_r_addr;
    reg [8-1:0] s_r_addr, s_w_addr;
    reg s_w_en;
    reg [DATA_WIDTH-1:0] s_w_data;
    reg [15:0] j_count;      // which K row (0..N-1)
    reg [15:0] k_count;      // which packed word (0..PACKED_D-1)

    wire q_w_en = (state == S_LOAD_Q) && valid_q;
    wire [DATA_WIDTH-1:0] q_sram_out;
    sram #(.N_CHANNELS(1),.DATA_WIDTH(DATA_WIDTH),.DEPTH(14))
        q_sram (.clk(clk),.rst(rst),.w_en(q_w_en),
                .r_addr(q_r_addr),.w_addr(q_w_addr),
                .sram_data_in(data_in_q),.sram_data_out(q_sram_out));

    wire k_w_en = (state == S_LOAD_K) && valid_k;
    wire [DATA_WIDTH-1:0] k_sram_out;
    sram #(.N_CHANNELS(1),.DATA_WIDTH(DATA_WIDTH),.DEPTH(1665))
        k_sram (.clk(clk),.rst(rst),.w_en(k_w_en),
                .r_addr(k_r_addr),.w_addr(k_w_addr),
                .sram_data_in(data_in_k),.sram_data_out(k_sram_out));

    wire [DATA_WIDTH-1:0] score_sram_out;
    sram #(.N_CHANNELS(1),.DATA_WIDTH(DATA_WIDTH),.DEPTH(129))
        score_sram (.clk(clk),.rst(rst),.w_en(s_w_en),
                    .r_addr(s_r_addr),.w_addr(s_w_addr),
                    .sram_data_in(s_w_data),.sram_data_out(score_sram_out));

    // DSP MAC: K=PACKED_D accumulation over packed pairs of Q, K[j]
    wire dsp_valid = (state == S_COMPUTE) && (mac_count >= 2);  // 2-cyc SRAM latency
    wire [DATA_WIDTH-1:0] dsp_out;
    wire dsp_out_valid;
    reg [15:0] mac_count;

    dsp_mac #(.DATA_WIDTH(DATA_WIDTH), .K(PACKED_D)) mac_inst (
        .clk(clk), .rst(rst),
        .valid(dsp_valid), .ready_n(1'b0),
        .data_a(q_sram_out),
        .data_b(k_sram_out),
        .data_out(dsp_out),
        .ready(), .valid_n(dsp_out_valid)
    );

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= S_IDLE;
            q_w_addr <= 0; q_r_addr <= 0;
            k_w_addr <= 0; k_r_addr <= 0;
            s_r_addr <= 0; s_w_addr <= 0; s_w_en <= 0; s_w_data <= 0;
            j_count <= 0; k_count <= 0; mac_count <= 0;
        end else begin
            s_w_en <= 0;   // default
            case (state)
                S_IDLE: if (valid_q || valid_k) state <= S_LOAD_Q;
                S_LOAD_Q: begin
                    if (valid_q) q_w_addr <= q_w_addr + 1;
                    if (q_w_addr == PACKED_D) state <= S_LOAD_K;
                end
                S_LOAD_K: begin
                    if (valid_k) k_w_addr <= k_w_addr + 1;
                    if (k_w_addr == N * PACKED_D) begin
                        state <= S_COMPUTE;
                        j_count <= 0; k_count <= 0; mac_count <= 0;
                    end
                end
                S_COMPUTE: begin
                    // Set SRAM addresses each cycle (2-cyc latency)
                    if (k_count < PACKED_D) begin
                        q_r_addr <= k_count;
                        k_r_addr <= j_count * PACKED_D + k_count;
                    end
                    mac_count <= mac_count + 1;
                    if (mac_count < PACKED_D + 1) k_count <= k_count + 1;
                    // When dsp_mac finishes a row: capture score and advance j
                    if (dsp_out_valid) begin
                        s_w_data <= dsp_out;
                        s_w_addr <= j_count;
                        s_w_en <= 1;
                        if (j_count == N - 1) state <= S_OUTPUT;
                        else begin
                            j_count <= j_count + 1;
                            k_count <= 0;
                            mac_count <= 0;
                        end
                    end
                end
                S_OUTPUT: begin
                    if (!ready_n) begin
                        s_r_addr <= s_r_addr + 1;
                        if (s_r_addr == N - 1) state <= S_IDLE;
                    end
                end
            endcase
        end
    end

    assign valid_n = (state == S_OUTPUT);
    assign data_out = score_sram_out;

endmodule

module dsp_mac #(
    parameter DATA_WIDTH = 40,
    parameter K = 64
)(
    input  wire                   clk, rst, valid, ready_n,
    input  wire [DATA_WIDTH-1:0]  data_a,
    input  wire [DATA_WIDTH-1:0]  data_b,
    output wire [DATA_WIDTH-1:0]  data_out,
    output wire                   ready, valid_n
);
    localparam ADDR_W = $clog2(K+1);
    reg [ADDR_W-1:0] count;
    reg out_valid;

    // Unpack 5 × int8 → 9-bit sign-extended for sop_4 ports
    wire [8:0] ax = {data_a[ 7], data_a[ 7: 0]};   // element 0
    wire [8:0] ay = {data_b[ 7], data_b[ 7: 0]};
    wire [8:0] bx = {data_a[15], data_a[15: 8]};   // element 1
    wire [8:0] by = {data_b[15], data_b[15: 8]};
    wire [8:0] cx = {data_a[23], data_a[23:16]};   // element 2
    wire [8:0] cy = {data_b[23], data_b[23:16]};
    wire [8:0] dx = {data_a[31], data_a[31:24]};   // element 3
    wire [8:0] dy = {data_b[31], data_b[31:24]};
    // Element 4: handled by feeding into ax/ay on a second sub-cycle,
    // or by a separate small CLB multiply. For simplicity, use CLB:
    wire signed [17:0] p4 = $signed(data_a[39:32]) * $signed(data_b[39:32]);

    wire [63:0] sop_result;
    wire [63:0] sop_chainout;

    // int_sop_4: result = ax*ay + bx*by + cx*cy + dx*dy + chainin
    int_sop_4 sop_inst (
        .clk(clk),
        .reset(rst),
        .mode_sigs(12'b0),
        .ax(ax), .ay(ay),
        .bx(bx), .by(by),
        .cx(cx), .cy(cy),
        .dx(dx), .dy(dy),
        .chainin(64'b0),
        .result(sop_result),
        .chainout(sop_chainout)
    );

    // Per-cycle: 4 products from sop_4 + 5th element from CLB
    wire signed [DATA_WIDTH-1:0] cycle_sum = sop_result[DATA_WIDTH-1:0] + {{22{p4[17]}}, p4};
    reg signed [DATA_WIDTH-1:0] accum;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            accum <= 0; count <= 0; out_valid <= 0;
        end else if (valid) begin
            if (count == 0)
                accum <= cycle_sum;
            else
                accum <= accum + cycle_sum;
            if (count == K - 1) begin
                count <= 0;
                out_valid <= 1;
            end else begin
                count <= count + 1;
                out_valid <= 0;
            end
        end else begin
            out_valid <= 0;
        end
    end
    assign data_out = accum;
    assign valid_n = out_valid;
    assign ready = 1'b1;
endmodule

module sram #(
    parameter N_CHANNELS = 1,
    parameter DATA_WIDTH = 40*N_CHANNELS,  // Data width (default: 16 bits) 16 x number of channels
    parameter DEPTH = 512       // Memory depth (default: 512)

)(
    input wire clk,
    input wire w_en,
	input wire rst,
    input wire [$clog2(DEPTH)-1:0] r_addr,
    input wire [$clog2(DEPTH)-1:0] w_addr,
    input wire [DATA_WIDTH-1:0] sram_data_in,
    output reg [DATA_WIDTH-1:0] sram_data_out
);

    // Memory array with parameterized depth and width
    reg [DATA_WIDTH-1:0] mem [DEPTH-1:0];

    // Read/Write operations
    always @(posedge clk) begin
        if (rst) begin
            sram_data_out <= {DATA_WIDTH{1'b0}};
        end else begin
            sram_data_out <= mem[r_addr];
        end
    end
    always @(posedge clk) begin
            if (w_en) begin
                mem[w_addr] <= sram_data_in;
            end
    end

endmodule